CREATE TABLE IF NOT EXISTS geo_publications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL, draft_id UUID, query_id UUID, title TEXT NOT NULL, url TEXT NOT NULL, platform TEXT, published_at TIMESTAMPTZ, status TEXT NOT NULL DEFAULT 'live', notes TEXT, last_check_at TIMESTAMPTZ, last_check_found BOOLEAN, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());